import requests
import json
from requests.auth import HTTPBasicAuth
import os
from typing import Dict, List, Optional

class KongAdminClient:
    def __init__(self, base_url: str, admin_token: Optional[str] = None, username: Optional[str] = None, password: Optional[str] = None):
        self.base_url = base_url.rstrip('/')
        self.session = requests.Session()
        
        if admin_token:
            self.session.headers.update({'X-Kong-Admin-Token': admin_token})
        elif username and password:
            self.session.auth = HTTPBasicAuth(username, password)
        else:
            raise ValueError("Either admin_token or username/password must be provided")
    
    def _make_request(self, method: str, endpoint: str, data: Optional[Dict] = None, **kwargs) -> requests.Response:
        url = f"{self.base_url}{endpoint}"
        response = self.session.request(
            method=method,
            url=url,
            json=data,
            **kwargs
        )
        response.raise_for_status()
        return response
    
    def create_service(self, service_name: str, url: str, **kwargs) -> Dict:
        service_data = {
            "name": service_name,
            "url": url,
            **kwargs
        }
        response = self._make_request('POST', '/services', service_data)
        return response.json()
    
    def create_route(self, service_id: str, routes: List[Dict]) -> List[Dict]:
        created_routes = []
        for route in routes:
            route_data = {
                "service": {"id": service_id},
                **route
            }
            response = self._make_request('POST', '/routes', route_data)
            created_routes.append(response.json())
        return created_routes
    
    def create_upstream(self, upstream_name: str, **kwargs) -> Dict:
        upstream_data = {
            "name": upstream_name,
            **kwargs
        }
        response = self._make_request('POST', '/upstreams', upstream_data)
        return response.json()
    
    def create_target(self, upstream_id: str, target: str, **kwargs) -> Dict:
        target_data = {
            "target": target,
            **kwargs
        }
        response = self._make_request('POST', f'/upstreams/{upstream_id}/targets', target_data)
        return response.json()
    
    def get_service(self, service_id: str) -> Dict:
        response = self._make_request('GET', f'/services/{service_id}')
        return response.json()
    
    def get_route(self, route_id: str) -> Dict:
        response = self._make_request('GET', f'/routes/{route_id}')
        return response.json()
    
    def get_upstream(self, upstream_id: str) -> Dict:
        response = self._make_request('GET', f'/upstreams/{upstream_id}')
        return response.json()
    
    def delete_service(self, service_id: str) -> bool:
        response = self._make_request('DELETE', f'/services/{service_id}')
        return response.status_code == 204
    
    def delete_route(self, route_id: str) -> bool:
        response = self._make_request('DELETE', f'/routes/{route_id}')
        return response.status_code == 204
    
    def delete_upstream(self, upstream_id: str) -> bool:
        response = self._make_request('DELETE', f'/upstreams/{upstream_id}')
        return response.status_code == 204

def main():
    # Configuration
    KONG_ADMIN_URL = os.getenv('KONG_ADMIN_URL', 'http://localhost:8001')
    ADMIN_TOKEN = os.getenv('KONG_ADMIN_TOKEN')
    USERNAME = os.getenv('KONG_ADMIN_USERNAME')
    PASSWORD = os.getenv('KONG_ADMIN_PASSWORD')
    
    # Initialize client
    client = KongAdminClient(
        base_url=KONG_ADMIN_URL,
        admin_token=ADMIN_TOKEN,
        username=USERNAME,
        password=PASSWORD
    )
    
    try:
        # Create service
        service = client.create_service(
            service_name="example-service",
            url="http://httpbin.org"
        )
        print(f"Created service: {service['name']}")
        
        # Create routes
        routes = client.create_route(
            service_id=service['id'],
            routes=[
                {
                    "paths": ["/example"],
                    "methods": ["GET"]
                },
                {
                    "paths": ["/api/*"],
                    "methods": ["POST", "PUT", "DELETE"]
                }
            ]
        )
        print(f"Created {len(routes)} routes")
        
        # Create upstream
        upstream = client.create_upstream(
            upstream_name="example-upstream",
            algorithm="round-robin"
        )
        print(f"Created upstream: {upstream['name']}")
        
        # Create targets
        targets = [
            client.create_target(upstream_id=upstream['id'], target="127.0.0.1:8080"),
            client.create_target(upstream_id=upstream['id'], target="127.0.0.1:8081")
        ]
        print(f"Created {len(targets)} targets")
        
        # Verify configuration
        service_details = client.get_service(service['id'])
        print(f"Service details: {service_details['name']}")
        
        upstream_details = client.get_upstream(upstream['id'])
        print(f"Upstream details: {upstream_details['name']}")
        
    except requests.exceptions.RequestException as e:
        print(f"Error communicating with Kong: {e}")
        raise
    except Exception as e:
        print(f"Error: {e}")
        raise

if __name__ == "__main__":
    main()